1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Damage {
13	  itemType: string;
14	  amount: number;
15	}
16	
17	interface Incident {
18	  cause: string;
19	  damages: Damage[];
20	}
21	
22	interface ClaimStep {
23	  op: "claim";
24	  policy: number;
25	  incident: Incident;
26	}
27	
28	type Step = QuoteStep | ClaimStep;
29	
30	interface Scenario {
31	  customer: { yearsWithMHPCO: number };
32	  steps: Step[];
33	}
34	
35	const BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	  staff: 80,
39	  potion: 40,
40	};
41	
42	const COMPONENT_PREMIUM = 25;
43	const COMPONENT_BLOCK_SIZE = 3;
44	const COMPONENT_BLOCK_PREMIUM = 60;
45	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
46	
47	const INSURANCE_VALUE: Record<string, number> = {
48	  sword: 1000,
49	  amulet: 600,
50	  staff: 800,
51	  potion: 400,
52	};
53	const COMPONENT_INSURANCE_VALUE = 250;
54	
55	const DEDUCTIBLE = 100;
56	const CAP_MULTIPLIER = 2;
57	const HALF_REIMBURSEMENT_ENCHANTMENT = 8;
58	const HALF_REIMBURSEMENT_RATE = 0.5;
59	
60	const FIRST_INSURANCE_SURCHARGE = 1.1;
61	const CURSE_SURCHARGE_RATE = 0.5;
62	const HIGH_ENCHANTMENT_THRESHOLD = 5;
63	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
64	const LOYALTY_THRESHOLD_YEARS = 2;
65	const LOYALTY_DISCOUNT_RATE = 0.2;
66	const FOLLOWUP_DISCOUNT_RATE = 0.15;
67	const PROCESSING_FEE = 5;
68	
69	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
70	
71	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
72	
73	// Base premium of a single item (main item or one component).
74	const itemBase = (item: Item): number =>
75	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
76	
77	// A surcharge adds `rate` of the base premium for each affected item.
78	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
79	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
80	
81	// Curse adds 50% of the affected item's base premium.
82	const curseSurcharge = (items: Item[]): number =>
83	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
84	
85	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
86	const enchantmentSurcharge = (items: Item[]): number =>
87	  surchargeFor(
88	    items,
89	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
90	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
91	  );
92	
93	// Base premium for `count` alike components: a group of exactly 3 forms a
94	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
95	// COMPONENT_PREMIUM.
96	const componentGroupPremium = (count: number): number =>
97	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
98	
99	// Count how many alike components of each type appear (e.g. { rune: 2 }).
100	const countByType = (items: Item[]): Map<string, number> =>
101	  items.reduce((counts, item) => {
102	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
103	    return counts;
104	  }, new Map<string, number>());
105	
106	const mainItemsPremium = (items: Item[]): number =>
107	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
108	
109	const componentsPremium = (items: Item[]): number =>
110	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
111	
112	const basePremium = (items: Item[]): number =>
113	  mainItemsPremium(items) + componentsPremium(items);
114	
115	// Insurance value of a single item (main item or one component).
116	const insuranceValue = (item: Item): number =>
117	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : (INSURANCE_VALUE[item.type] ?? 0);
118	
119	// Snap away floating-point noise (e.g. 197.5000000001) by rounding to 6
120	// decimal places, so a subsequent ceil/floor lands on the intended whole G.
121	const FLOAT_GUARD_PRECISION = 1e6;
122	const snapFloat = (value: number): number =>
123	  Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION;
124	
125	// Round up to a whole number in MHPCO's favour.
126	const roundUpToWhole = (value: number): number => Math.ceil(snapFloat(value));
127	
128	// Round a payout down to whole G, in MHPCO's favour.
129	const roundDownToWhole = (value: number): number => Math.floor(snapFloat(value));
130	
131	// A policy-wide discount takes `rate` of the policy base when it applies.
132	const discount = (applies: boolean, rate: number, base: number): number =>
133	  applies ? rate * base : 0;
134	
135	// Long-standing customers (>= 2 years) receive 20% off the policy base.
136	const loyaltyDiscount = (base: number, yearsWithMHPCO: number): number =>
137	  discount(yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS, LOYALTY_DISCOUNT_RATE, base);
138	
139	// Every quote after the customer's first receives 15% off the policy base.
140	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
141	  discount(isFollowUp, FOLLOWUP_DISCOUNT_RATE, base);
142	
143	// Premium for one quote: base premium plus the first-insurance surcharge,
144	// item-specific curse/enchantment surcharges, less the policy-wide loyalty
145	// and follow-up discounts, and the flat processing fee.
146	const quotePremium = (items: Item[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
147	  const base = basePremium(items);
148	  return (
149	    base * FIRST_INSURANCE_SURCHARGE +
150	    curseSurcharge(items) +
151	    enchantmentSurcharge(items) -
152	    loyaltyDiscount(base, yearsWithMHPCO) -
153	    followUpDiscount(base, isFollowUp) +
154	    PROCESSING_FEE
155	  );
156	};
157	
158	// Reimbursable amount for damage to one item: halved for highly enchanted
159	// items (>= 8), otherwise the full damage amount.
160	const reimbursement = (item: Item, amount: number): number =>
161	  (item.enchantment ?? 0) >= HALF_REIMBURSEMENT_ENCHANTMENT
162	    ? HALF_REIMBURSEMENT_RATE * amount
163	    : amount;
164	
165	// Payout for one damage event: reimbursement less the per-event deductible.
166	const damagePayout = (item: Item, damage: Damage): number =>
167	  Math.max(0, reimbursement(item, damage.amount) - DEDUCTIBLE);
168	
169	// The policy item a damage applies to, matched by type. A damage whose item is
170	// not part of the policy is rejected.
171	const policyItemFor = (policy: Item[], damage: Damage): Item => {
172	  const item = policy.find((candidate) => candidate.type === damage.itemType);
173	  if (item === undefined) {
174	    throw new Error(`damaged item not in policy: ${damage.itemType}`);
175	  }
176	  return item;
177	};
178	
179	// Payout for one damage within a policy: match the item, then compute its payout.
180	const damagePayoutInPolicy = (policy: Item[], damage: Damage): number =>
181	  damagePayout(policyItemFor(policy, damage), damage);
182	
183	// Total cap for a policy: twice the sum of its items' insurance values.
184	const policyCap = (policy: Item[]): number => CAP_MULTIPLIER * sum(policy.map(insuranceValue));
185	
186	// Payout for a claim against a policy with `remainingCap` left: the desired
187	// reimbursement (per-damage, deductible applied) limited to the remaining cap.
188	const claimResult = (
189	  policy: Item[],
190	  incident: Incident,
191	  remainingCap: number,
192	): { payout: number; remainingCap: number } => {
193	  const desired = roundDownToWhole(
194	    sum(incident.damages.map((damage) => damagePayoutInPolicy(policy, damage))),
195	  );
196	  const payout = Math.min(desired, remainingCap);
197	  return { payout, remainingCap: remainingCap - payout };
198	};
199	
200	// What MHPCO remembers about each policy it has quoted: the insured items and
201	// how much of the claim cap is still available.
202	interface Policy {
203	  items: Item[];
204	  remainingCap: number;
205	}
206	
207	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
208	  const { yearsWithMHPCO } = scenario.customer;
209	  const policiesByStep: Record<number, Policy> = {};
210	  let quotesSeen = 0;
211	  const results = scenario.steps.map((step, index) => {
212	    if (step.op === "claim") {
213	      const policy = policiesByStep[step.policy];
214	      const result = claimResult(policy.items, step.incident, policy.remainingCap);
215	      policy.remainingCap = result.remainingCap;
216	      return result;
217	    }
218	    const isFollowUp = quotesSeen > 0;
219	    quotesSeen += 1;
220	    policiesByStep[index] = { items: step.items, remainingCap: policyCap(step.items) };
221	    return { premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO, isFollowUp)) };
222	  });
223	  return { results };
224	};
